import React from "react"
import Select from 'react-select'
import { properties } from '../../properties/properties.js'
import querystring from 'query-string'
import { Chart as ChartJS, registerables } from 'chart.js';
import { Bar } from 'react-chartjs-2'
ChartJS.register(...registerables);

class Report extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0
        };
    }







      componentDidMount() {



        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `getVoalteFamily`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})
            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }






          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {
              header = ""
              var content = []



                this.state.results.map(rec => {

                    content.push(<div><hr></hr><h2>{rec.unit}</h2></div>)


                    var dataset = []
                    var i = 0
                    var colorBar = ["blue", "green", "orange", "red"]

                  var tableContent = []

                  var tableStyle = {
                    "border": "1px solid black"
                 };

                    rec.data.map(rec2 => {

                        var totalMessage = rec2.totalMessage
                        var familyMembersEnrolled = rec2.familyMembersEnrolled
                        var uniquePatients = rec2.uniquePatients
                        var uniqueMsgPatients = rec2.uniqueMsgPatients
                        var uniqueFamilyPatients = rec2.uniqueFamilyPatients
                        var graphData = []
                        graphData.push(totalMessage)
                        graphData.push(familyMembersEnrolled)
                        graphData.push(uniqueFamilyPatients)

                        var avgMessage = 0
                        if (uniqueMsgPatients == 0) {
                            graphData.push(0)
                        } else {
                            avgMessage = totalMessage / uniqueMsgPatients
                            graphData.push(totalMessage / uniqueMsgPatients)
                        }
                        graphData.push(uniquePatients)


                        dataset.push({label: rec2.month + "/" + rec2.year, data: graphData, backgroundColor: colorBar[i%4]})


                        tableContent.push(<tr><tb style={tableStyle}>{rec2.month+"/"+rec2.year}</tb><td style={tableStyle}>{totalMessage}</td><td style={tableStyle}>{familyMembersEnrolled}</td><td style={tableStyle}>{uniqueFamilyPatients}</td><td style={tableStyle}>{avgMessage}</td><td style={tableStyle}>{uniquePatients}</td></tr>)

                        i += 1
                    })




                    content.push(<div><Bar 
                        height={400} 
                        width={400} 
                        data={{
                          labels: ["Total Messages and Photos", "Voalte Family Members Enrolled", "Voalte Family Patients active during the month", "Average Messages Per Patient","Voalte Family Newly enrolled Patients"],
                          datasets: dataset


                        }} 
                        options={{maintainAspectRatio: false}}

                        ></Bar></div>)


                      content.push(<div><br></br><table><tr><td style={tableStyle}>Month</td><td style={tableStyle}>Total Messages and Photos</td><td style={tableStyle}>Voalte Family Members Enrolled</td><td style={tableStyle}>Voalte Family Patients active during the month</td><td style={tableStyle}>Average Messages Per Patient</td><td style={tableStyle}>Voalte Family Newly enrolled Patients</td></tr>{tableContent}</table></div>)



                })










          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Report
